# ============= LOCALIZATION =============
$script:lang = @{}

function Load-Language {
    param($langFile)
    if (Test-Path $langFile) {
        $lines = Get-Content $langFile -Encoding UTF8
        foreach ($line in $lines) {
            if ($line -match "^#.*$" -or [string]::IsNullOrWhiteSpace($line)) { continue }
            if ($line -match "^([^=]+)=(.*)$") {
                $key = $matches[1].Trim()
                $value = $matches[2].Trim()
                $script:lang[$key] = $value
            }
        }
        return $true
    }
    return $false
}

function Get-Lang {
    param($key, $default = "")
    if ($script:lang.ContainsKey($key)) { return $script:lang[$key] }
    return $default
}

# ============= CONFIGURATION =============
$script:pdftk = $null
$script:gs = $null
$script:qpdf = $null

$script:scriptDir = Split-Path -Parent -Path $MyInvocation.MyCommand.Definition
$script:libsDir = $null

# Find LIBS folder
$possiblePaths = @(
    [System.IO.Path]::Combine($script:scriptDir, "LIBS"),
    $script:scriptDir
)

foreach ($path in $possiblePaths) {
    $testPath = [System.IO.Path]::GetFullPath($path)
    if (Test-Path $testPath) {
        if ((Test-Path ([System.IO.Path]::Combine($testPath, "gs"))) -or `
            (Test-Path ([System.IO.Path]::Combine($testPath, "PDFtk Server"))) -or `
            (Test-Path ([System.IO.Path]::Combine($testPath, "qpdf")))) {
            $script:libsDir = $testPath
            break
        }
    }
}

if (-not $script:libsDir) {
    $script:libsDir = $script:scriptDir
}

# Load language file
$script:langFile = [System.IO.Path]::Combine($script:libsDir, "aze.lang")
$script:languageLoaded = Load-Language $script:langFile

if (-not $script:languageLoaded) {
    Write-Host "Warning: Language file not found at $script:langFile" -ForegroundColor Yellow
}

# ============= TOOL DETECTION - RECURSIVE SEARCH =============

function Find-Pdftk {
    Write-Host "  Searching for pdftk.exe..." -ForegroundColor Gray
    try {
        $pdftkFiles = Get-ChildItem -Path $script:libsDir -Filter "pdftk.exe" -Recurse -ErrorAction SilentlyContinue
        foreach ($f in $pdftkFiles) {
            Write-Host "    Found: $($f.FullName)" -ForegroundColor Green
            return $f.FullName
        }
    } catch { }
    $paths = @(
        [System.IO.Path]::Combine($script:libsDir, "PDFtk Server", "bin", "pdftk.exe"),
        [System.IO.Path]::Combine($script:libsDir, "PDFtk", "bin", "pdftk.exe"),
        [System.IO.Path]::Combine($script:libsDir, "pdftk.exe")
    )
    foreach ($p in $paths) {
        if (Test-Path $p) { Write-Host "    Found: $p" -ForegroundColor Green; return $p }
    }
    try {
        $p = (Get-Command pdftk.exe -ErrorAction SilentlyContinue)
        if ($p) { Write-Host "    Found in PATH: $($p.Source)" -ForegroundColor Green; return $p.Source }
    } catch { }
    Write-Host "    pdftk.exe NOT FOUND!" -ForegroundColor Red
    return $null
}

function Find-Ghostscript {
    Write-Host "  Searching for Ghostscript..." -ForegroundColor Gray
    try {
        $gsFiles = Get-ChildItem -Path $script:libsDir -Filter "gswin64c.exe" -Recurse -ErrorAction SilentlyContinue
        foreach ($f in $gsFiles) { Write-Host "    Found: $($f.FullName)" -ForegroundColor Green; return $f.FullName }
    } catch { }
    try {
        $gsFiles = Get-ChildItem -Path $script:libsDir -Filter "gswin32c.exe" -Recurse -ErrorAction SilentlyContinue
        foreach ($f in $gsFiles) { Write-Host "    Found: $($f.FullName)" -ForegroundColor Green; return $f.FullName }
    } catch { }
    $gsBase = [System.IO.Path]::Combine($script:libsDir, "gs")
    if (Test-Path $gsBase) {
        $folders = Get-ChildItem -Path $gsBase -Directory -ErrorAction SilentlyContinue | Sort-Object Name -Descending
        foreach ($f in $folders) {
            $test = [System.IO.Path]::Combine($f.FullName, "bin", "gswin64c.exe")
            if (Test-Path $test) { Write-Host "    Found: $test" -ForegroundColor Green; return $test }
            $test = [System.IO.Path]::Combine($f.FullName, "bin", "gswin32c.exe")
            if (Test-Path $test) { Write-Host "    Found: $test" -ForegroundColor Green; return $test }
        }
    }
    $direct = @(
        [System.IO.Path]::Combine($script:libsDir, "gswin64c.exe"),
        [System.IO.Path]::Combine($script:libsDir, "gswin32c.exe")
    )
    foreach ($p in $direct) {
        if (Test-Path $p) { Write-Host "    Found: $p" -ForegroundColor Green; return $p }
    }
    try { $p = (Get-Command gswin64c.exe -ErrorAction SilentlyContinue); if ($p) { Write-Host "    Found in PATH: $($p.Source)" -ForegroundColor Green; return $p.Source } } catch { }
    try { $p = (Get-Command gswin32c.exe -ErrorAction SilentlyContinue); if ($p) { Write-Host "    Found in PATH: $($p.Source)" -ForegroundColor Green; return $p.Source } } catch { }
    Write-Host "    Ghostscript NOT FOUND!" -ForegroundColor Red
    return $null
}

function Find-QPDF {
    Write-Host "  Searching for qpdf.exe..." -ForegroundColor Gray
    try {
        $qpdfFiles = Get-ChildItem -Path $script:libsDir -Filter "qpdf.exe" -Recurse -ErrorAction SilentlyContinue
        foreach ($f in $qpdfFiles) { Write-Host "    Found: $($f.FullName)" -ForegroundColor Green; return $f.FullName }
    } catch { }
    $paths = @(
        [System.IO.Path]::Combine($script:libsDir, "qpdf", "bin", "qpdf.exe"),
        [System.IO.Path]::Combine($script:libsDir, "qpdf.exe"),
        [System.IO.Path]::Combine($script:scriptDir, "LIBS", "qpdf", "bin", "qpdf.exe"),
        [System.IO.Path]::Combine($script:scriptDir, "LIBS", "qpdf.exe")
    )
    foreach ($p in $paths) { if (Test-Path $p) { Write-Host "    Found: $p" -ForegroundColor Green; return $p } }
    try { $p = (Get-Command qpdf.exe -ErrorAction SilentlyContinue); if ($p) { Write-Host "    Found in PATH: $($p.Source)" -ForegroundColor Green; return $p.Source } } catch { }
    Write-Host "    qpdf.exe NOT FOUND!" -ForegroundColor Red
    return $null
}

# ============= FIND TOOLS =============
Write-Host "`n" + "="*60 -ForegroundColor Cyan
Write-Host "SEARCHING FOR TOOLS IN: $script:libsDir" -ForegroundColor Yellow
Write-Host "="*60 -ForegroundColor Cyan
Write-Host ""

$script:pdftk = Find-Pdftk
$script:gs    = Find-Ghostscript
$script:qpdf  = Find-QPDF

Write-Host ""
Write-Host "="*60 -ForegroundColor Cyan

if (-not $script:pdftk -or -not $script:gs -or -not $script:qpdf) {
    $missing = @()
    if (-not $script:pdftk) { $missing += "PDFtk" }
    if (-not $script:gs)    { $missing += "Ghostscript" }
    if (-not $script:qpdf)  { $missing += "QPDF" }
    
    $msg = "Missing tools: $($missing -join ', ')!`n`n"
    $msg += "Please place these files in the LIBS folder:`n"
    if (-not $script:pdftk) { $msg += "  - pdftk.exe`n" }
    if (-not $script:gs)    { $msg += "  - gswin64c.exe or gswin32c.exe`n" }
    if (-not $script:qpdf)  { $msg += "  - qpdf.exe`n" }
    $msg += "`nThey can be in subfolders - script will find them recursively."
    
    [System.Windows.Forms.MessageBox]::Show($msg, "Tools Missing", "OK", "Error")
    exit
}

Write-Host ""
Write-Host "ALL TOOLS FOUND!" -ForegroundColor Green
Write-Host "  PDFtk: $script:pdftk" -ForegroundColor Green
Write-Host "  Ghostscript: $script:gs" -ForegroundColor Green
Write-Host "  QPDF: $script:qpdf" -ForegroundColor Green
Write-Host "="*60 -ForegroundColor Cyan
Write-Host ""

# ============= UNICODE SUPPORT FUNCTIONS =============
function Get-ShortPath {
    param($Path)
    try {
        $shortPathBuilder = New-Object System.Text.StringBuilder(260)
        $getShortPathName = Add-Type -MemberDefinition @'
[DllImport("kernel32.dll", CharSet = CharSet.Unicode, SetLastError = true)]
public static extern int GetShortPathNameW(string lpszLongPath, System.Text.StringBuilder lpszShortPath, int cchBuffer);
'@ -Name "Kernel32" -Namespace "Win32" -PassThru -ErrorAction SilentlyContinue
        if ($getShortPathName) {
            $result = $getShortPathName::GetShortPathNameW($Path, $shortPathBuilder, 260)
            if ($result -gt 0) {
                $shortPath = $shortPathBuilder.ToString()
                if ($shortPath) { return $shortPath }
            }
        }
    } catch { }
    return $Path
}

# ============= POPUP "WORKING..." DIALOG (MARQUEE) =============
$script:workingForm  = $null
$script:workingLabel = $null

function Show-WorkingDialog {
    param([string]$Message = "Working... Please Wait...")
    if ($script:workingForm -and -not $script:workingForm.IsDisposed) {
        $script:workingLabel.Text = $Message
        $script:workingForm.Show()
        $script:workingForm.BringToFront()
        [System.Windows.Forms.Application]::DoEvents()
        return
    }
    $wf = New-Object System.Windows.Forms.Form
    $wf.Text = "Please Wait"
    $wf.Size = New-Object System.Drawing.Size(420, 140)
    $wf.StartPosition = "CenterParent"
    $wf.FormBorderStyle = "FixedDialog"
    $wf.MaximizeBox = $false
    $wf.MinimizeBox = $false
    $wf.ControlBox  = $false
    $wf.TopMost     = $true
    $wf.ShowInTaskbar = $false
    $wf.BackColor   = [System.Drawing.Color]::White

    $lbl = New-Object System.Windows.Forms.Label
    $lbl.Text = $Message
    $lbl.AutoSize = $false
    $lbl.Size = New-Object System.Drawing.Size(380, 30)
    $lbl.Location = New-Object System.Drawing.Point(20, 20)
    $lbl.Font = New-Object System.Drawing.Font("Segoe UI", 11, [System.Drawing.FontStyle]::Bold)
    $lbl.TextAlign = "MiddleCenter"
    $wf.Controls.Add($lbl)

    $pb = New-Object System.Windows.Forms.ProgressBar
    $pb.Style = 'Marquee'
    $pb.MarqueeAnimationSpeed = 30
    $pb.Size = New-Object System.Drawing.Size(380, 26)
    $pb.Location = New-Object System.Drawing.Point(20, 60)
    $wf.Controls.Add($pb)

    $script:workingForm  = $wf
    $script:workingLabel = $lbl
    $wf.Show()
    [System.Windows.Forms.Application]::DoEvents()
}

function Update-WorkingMessage {
    param([string]$Message)
    if ($script:workingForm -and -not $script:workingForm.IsDisposed -and $script:workingLabel) {
        $script:workingLabel.Text = $Message
        $script:workingForm.Refresh()
        [System.Windows.Forms.Application]::DoEvents()
    }
}

function Hide-WorkingDialog {
    if ($script:workingForm -and -not $script:workingForm.IsDisposed) {
        $script:workingForm.Hide()
        $script:workingForm.Dispose()
    }
    $script:workingForm  = $null
    $script:workingLabel = $null
    [System.Windows.Forms.Application]::DoEvents()
}

# ============= SMART PDF ANALYZER =============
function Wait-ProcWithDoEvents {
    param([System.Diagnostics.Process]$proc, [int]$timeoutMS = 0)
    $start = Get-Date
    while (-not $proc.HasExited) {
        Start-Sleep -Milliseconds 100
        [System.Windows.Forms.Application]::DoEvents()
        if ($timeoutMS -gt 0 -and ((Get-Date) - $start).TotalMilliseconds -ge $timeoutMS) { break }
    }
}

function AnalyzePDF {
    param($inputFile)
    if (-not (Test-Path $inputFile)) { return $null }
    
    Write-Host "`n========================================" -ForegroundColor Cyan
    Write-Host "ANALYZING PDF FILE..." -ForegroundColor Yellow
    Write-Host "========================================" -ForegroundColor Cyan
    
    $analysis = @{
        FileSize = (Get-ChildItem $inputFile).Length
        FileSizeMB = [math]::Round((Get-ChildItem $inputFile).Length / 1MB, 2)
        PageCount = 0
        TextLength = 0
        TextPerPage = 0
        AvgSizePerPage = 0
        ContentType = "Unknown"
        RecommendedMethod = ""
        RecommendedMethodName = ""
        Reason = ""
        HasText = $false
        HasImages = $false
        IsMixedContent = $false
    }
    
    Write-Host "Analyzing pages..." -ForegroundColor Gray
    try {
        $tempInfo = [System.IO.Path]::GetTempFileName() + ".txt"
        $args = "-q -dNOPAUSE -dBATCH -sDEVICE=nullpage -dFirstPage=1 -dLastPage=9999 -sOutputFile=`"$tempInfo`" `"$inputFile`" 2>&1"
        
        $p = New-Object System.Diagnostics.ProcessStartInfo
        $p.FileName = $script:gs
        $p.Arguments = $args
        $p.UseShellExecute = $false
        $p.CreateNoWindow = $true
        $p.RedirectStandardError = $true
        $p.RedirectStandardOutput = $true
        
        $proc = [System.Diagnostics.Process]::Start($p)
        Wait-ProcWithDoEvents -proc $proc -timeoutMS 8000
        
        $output = $proc.StandardError.ReadToEnd()
        $pageMatches = [regex]::Matches($output, "Processing pages \d+ through (\d+)")
        if ($pageMatches.Count -gt 0) {
            $analysis.PageCount = [int]$pageMatches[0].Groups[1].Value
        }
        Remove-Item $tempInfo -Force -ErrorAction SilentlyContinue
    } catch { }
    
    if ($analysis.PageCount -eq 0) { $analysis.PageCount = 1 }
    Write-Host "Pages: $($analysis.PageCount)" -ForegroundColor Gray
    
    Write-Host "Analyzing content..." -ForegroundColor Gray
    try {
        $tempText = [System.IO.Path]::GetTempFileName() + ".txt"
        $args = "-q -dNOPAUSE -dBATCH -sDEVICE=txtwrite -dTextFormat=3 -sOutputFile=`"$tempText`" `"$inputFile`""
        
        $p = New-Object System.Diagnostics.ProcessStartInfo
        $p.FileName = $script:gs
        $p.Arguments = $args
        $p.UseShellExecute = $false
        $p.CreateNoWindow = $true
        $p.RedirectStandardError = $true
        
        $proc = [System.Diagnostics.Process]::Start($p)
        Wait-ProcWithDoEvents -proc $proc -timeoutMS 15000
        
        if (Test-Path $tempText) {
            $textContent = Get-Content $tempText -Raw -ErrorAction SilentlyContinue
            $analysis.TextLength = $textContent.Length
            Write-Host "Text extracted: $($analysis.TextLength) characters" -ForegroundColor Gray
            Remove-Item $tempText -Force -ErrorAction SilentlyContinue
        }
    } catch { }
    
    $analysis.AvgSizePerPage = $analysis.FileSize / $analysis.PageCount
    $avgSizeKB = [math]::Round($analysis.AvgSizePerPage / 1KB, 0)
    Write-Host "Avg size per page: $avgSizeKB KB" -ForegroundColor Gray
    
    $analysis.TextPerPage = if ($analysis.PageCount) { $analysis.TextLength / $analysis.PageCount } else { 0 }
    Write-Host "Text per page: $([math]::Round($analysis.TextPerPage, 0)) chars" -ForegroundColor Gray
    
    $hasText = $analysis.TextLength -gt 100
    $hasImages = $false
    $isMixedContent = $false
    $contentType = "Unknown"
    $reason = ""
    
    if ($hasText -and $analysis.AvgSizePerPage -gt 200KB) {
        $hasImages = $true; $isMixedContent = $true
        $contentType = "Mixed (Text + Images)"
        $reason = "Both text ($([math]::Round($analysis.TextPerPage,0)) chars/page) and images detected"
    } elseif ($hasText -and $analysis.AvgSizePerPage -le 200KB) {
        $contentType = "Text-Only"
        $reason = "Text document with $([math]::Round($analysis.TextPerPage,0)) characters per page"
    } elseif (-not $hasText -and $analysis.AvgSizePerPage -gt 100KB) {
        $hasImages = $true
        $contentType = "Image-Only / Scanned"
        $reason = "Image-based document - will apply aggressive image compression"
    } else {
        $contentType = "Text-Only"
        $reason = "Text document with minimal formatting"
    }
    $analysis.HasText = $hasText
    $analysis.HasImages = $hasImages
    $analysis.IsMixedContent = $isMixedContent
    $analysis.ContentType = $contentType
    $analysis.Reason = $reason
    
    Write-Host "`nDetermining best compression method..." -ForegroundColor Cyan
    if ($contentType -eq "Image-Only / Scanned" -or $contentType -eq "Mixed (Text + Images)") {
        $analysis.RecommendedMethod = "Image Optimized (45% Quality)"
        $analysis.RecommendedMethodName = "Image Optimized (45% Quality)"
    } elseif ($contentType -eq "Text-Only") {
        $analysis.RecommendedMethod = "Method 1: Ghostscript Font Subset (90%+)"
        $analysis.RecommendedMethodName = "Method 1: Ghostscript Font Subset (90%+)"
    } else {
        $analysis.RecommendedMethod = "Image Optimized (45% Quality)"
        $analysis.RecommendedMethodName = "Image Optimized (45% Quality)"
    }
    
    Write-Host "`n========================================" -ForegroundColor Green
    Write-Host "ANALYSIS COMPLETE" -ForegroundColor Green
    Write-Host "File size: $($analysis.FileSizeMB) MB" -ForegroundColor Yellow
    Write-Host "Pages: $($analysis.PageCount)" -ForegroundColor Yellow
    Write-Host "Text extracted: $($analysis.TextLength) chars" -ForegroundColor Yellow
    Write-Host "Text per page: $([math]::Round($analysis.TextPerPage, 0)) chars" -ForegroundColor Yellow
    Write-Host "Content Type: $contentType" -ForegroundColor Yellow
    Write-Host "Recommended: $($analysis.RecommendedMethod)" -ForegroundColor Green
    Write-Host "Reason: $($analysis.Reason)" -ForegroundColor Gray
    Write-Host "========================================" -ForegroundColor Green
    
    return $analysis
}

# ============= COMPRESSION METHODS (with DoEvents) =============
function Invoke-External {
    param([string]$FileName, [string]$Arguments)
    $p = New-Object System.Diagnostics.ProcessStartInfo
    $p.FileName = $FileName
    $p.Arguments = $Arguments
    $p.UseShellExecute = $false
    $p.CreateNoWindow = $true
    $p.RedirectStandardError = $true
    $p.RedirectStandardOutput = $true
    $proc = [System.Diagnostics.Process]::Start($p)
    while (-not $proc.HasExited) {
        Start-Sleep -Milliseconds 120
        [System.Windows.Forms.Application]::DoEvents()
    }
    $stderr = $proc.StandardError.ReadToEnd()
    $stdout = $proc.StandardOutput.ReadToEnd()
    return @{ ExitCode = $proc.ExitCode; StdErr = $stderr; StdOut = $stdout }
}

function CompressMethod_ImageOptimized {
    param($inputFile, $outputFile, $version, $imageQuality = 45)
    $jpegQuality = $imageQuality
    if ($jpegQuality -le 30) { $pdfSetting="screen"; $colorRes=72;  $grayRes=72;  $monoRes=150 }
    elseif ($jpegQuality -le 50){ $pdfSetting="screen"; $colorRes=100; $grayRes=100; $monoRes=200 }
    elseif ($jpegQuality -le 70){ $pdfSetting="ebook";  $colorRes=150; $grayRes=150; $monoRes=300 }
    else                        { $pdfSetting="printer";$colorRes=200; $grayRes=200; $monoRes=400 }
    $args = @(
        "-q","-dNOPAUSE","-dBATCH","-dSAFER","-sDEVICE=pdfwrite",
        "-dCompatibilityLevel=$version","-dPDFSETTINGS=/$pdfSetting",
        "-dSubsetFonts=true","-dEmbedAllFonts=true","-dCompressFonts=true",
        "-dRemoveUnusedObjects=true","-dRemoveUnusedFonts=true",
        "-dDownsampleColorImages=true","-dColorImageResolution=$colorRes",
        "-dDownsampleGrayImages=true","-dGrayImageResolution=$grayRes",
        "-dDownsampleMonoImages=true","-dMonoImageResolution=$monoRes",
        "-dJPEGQ=$jpegQuality",
        "-dAutoFilterColorImages=false","-dColorImageFilter=/DCTEncode",
        "-dAutoFilterGrayImages=false","-dGrayImageFilter=/DCTEncode",
        "-dCompressPages=true","-dCompressStreams=true","-dOptimize=true",
        "-dUseFlateCompression=true",
        "-sOutputFile=`"$outputFile`"","`"$inputFile`""
    ) -join " "
    $res = Invoke-External -FileName $script:gs -Arguments $args
    return ($res.ExitCode -eq 0 -and (Test-Path $outputFile) -and (Get-ChildItem $outputFile).Length -gt 0)
}

function CompressMethod1_FontSubset_Aggressive {
    param($inputFile, $outputFile, $version)
    $args = @(
        "-q","-dNOPAUSE","-dBATCH","-dSAFER","-sDEVICE=pdfwrite",
        "-dCompatibilityLevel=$version","-dPDFSETTINGS=/screen",
        "-dSubsetFonts=true","-dEmbedAllFonts=true","-dCompressFonts=true",
        "-dRemoveUnusedObjects=true","-dRemoveUnusedFonts=true","-dUseFlateCompression=true",
        "-sOutputFile=`"$outputFile`"","`"$inputFile`""
    ) -join " "
    $res = Invoke-External -FileName $script:gs -Arguments $args
    return ($res.ExitCode -eq 0 -and (Test-Path $outputFile) -and (Get-ChildItem $outputFile).Length -gt 0)
}

function CompressMethod_Balanced {
    param($inputFile, $outputFile, $version)
    $args = @(
        "-q","-dNOPAUSE","-dBATCH","-dSAFER","-sDEVICE=pdfwrite",
        "-dCompatibilityLevel=$version","-dPDFSETTINGS=/ebook",
        "-dSubsetFonts=true","-dEmbedAllFonts=true","-dCompressFonts=true",
        "-dRemoveUnusedObjects=true","-dRemoveUnusedFonts=true",
        "-dCompressPages=true","-dCompressStreams=true","-dOptimize=true",
        "-dUseFlateCompression=true",
        "-dDownsampleColorImages=true","-dColorImageResolution=200",
        "-dDownsampleGrayImages=true","-dGrayImageResolution=200",
        "-dAutoFilterColorImages=false","-dColorImageFilter=/FlateEncode",
        "-dAutoFilterGrayImages=false","-dGrayImageFilter=/FlateEncode",
        "-sOutputFile=`"$outputFile`"","`"$inputFile`""
    ) -join " "
    $res = Invoke-External -FileName $script:gs -Arguments $args
    return ($res.ExitCode -eq 0 -and (Test-Path $outputFile) -and (Get-ChildItem $outputFile).Length -gt 0)
}

function CompressMethod4_Rebuild {
    param($inputFile, $outputFile, $version)
    $tempText = [System.IO.Path]::GetTempFileName() + ".txt"
    try {
        $args = "-q -dNOPAUSE -dBATCH -sDEVICE=txtwrite -dTextFormat=3 -sOutputFile=`"$tempText`" `"$inputFile`""
        $res = Invoke-External -FileName $script:gs -Arguments $args
        if ($res.ExitCode -ne 0 -or -not (Test-Path $tempText) -or (Get-ChildItem $tempText).Length -eq 0) {
            Remove-Item $tempText -Force -ErrorAction SilentlyContinue
            return $false
        }
        $args2 = "-q -dNOPAUSE -dBATCH -sDEVICE=pdfwrite -dCompatibilityLevel=$version -dPDFSETTINGS=/screen -dSubsetFonts=true -dEmbedAllFonts=true -dCompressFonts=true -dRemoveUnusedObjects=true -dRemoveUnusedFonts=true -dUseFlateCompression=true -sOutputFile=`"$outputFile`" `"$tempText`""
        $res2 = Invoke-External -FileName $script:gs -Arguments $args2
        Remove-Item $tempText -Force -ErrorAction SilentlyContinue
        return ($res2.ExitCode -eq 0 -and (Test-Path $outputFile) -and (Get-ChildItem $outputFile).Length -gt 0)
    } catch {
        Remove-Item $tempText -Force -ErrorAction SilentlyContinue
        return $false
    }
}

function CompressMethod5_MaximalPlusStrip {
    param($inputFile, $outputFile, $version)
    $temp1 = [System.IO.Path]::GetTempFileName() + ".pdf"
    $temp2 = [System.IO.Path]::GetTempFileName() + ".pdf"
    $result1 = CompressMethod_Balanced $inputFile $temp1 $version
    if (-not $result1) { Remove-Item $temp1 -Force -ErrorAction SilentlyContinue; return $false }
    $args = "`"$temp1`" output `"$temp2`" compress flate"
    $res = Invoke-External -FileName $script:pdftk -Arguments $args
    Remove-Item $temp1 -Force -ErrorAction SilentlyContinue
    if ($res.ExitCode -eq 0 -and (Test-Path $temp2) -and (Get-ChildItem $temp2).Length -gt 0) {
        $result2 = CompressMethod1_FontSubset_Aggressive $temp2 $outputFile $version
        Remove-Item $temp2 -Force -ErrorAction SilentlyContinue
        return $result2
    }
    Remove-Item $temp2 -Force -ErrorAction SilentlyContinue
    return $false
}

# ============= SMART COMPRESSION ENGINE (UI-thread, popup) =============
function CompressFileSmart {
    param($inputFile, $outputFile)
    if (-not (Test-Path $inputFile)) { return $false }
    
    Update-WorkingMessage "Working... Please wait (analyzing)..."
    $analysis = AnalyzePDF $inputFile
    if (-not $analysis) {
        [System.Windows.Forms.MessageBox]::Show("Failed to analyze PDF file.", "Error", "OK", "Error")
        return $false
    }
    
    $inputSize = $analysis.FileSize
    $inputMB   = $analysis.FileSizeMB
    $version   = $cmbVersion.SelectedItem.ToString()
    $selectedMethod = $cmbMethod.SelectedItem.ToString()
    $imageQuality   = [int]$trackQuality.Value
    
    $useMethodName = ""
    $useFunction = $null
    if ($selectedMethod -like "*Intelligent*" -or $selectedMethod -like "*Auto*") {
        if ($analysis.ContentType -eq "Image-Only / Scanned" -or $analysis.HasImages -or $analysis.ContentType -eq "Mixed (Text + Images)") {
            $useMethodName = "Image Optimized ($imageQuality% Quality)"
            $useFunction   = { CompressMethod_ImageOptimized $inputFile $args[0] $version $imageQuality }
        } else {
            $useMethodName = "Method 1: Ghostscript Font Subset (90%+)"
            $useFunction   = { CompressMethod1_FontSubset_Aggressive $inputFile $args[0] $version }
        }
    } elseif ($selectedMethod -like "*Image Optimized*") {
        $useMethodName = "Image Optimized ($imageQuality% Quality)"
        $useFunction   = { CompressMethod_ImageOptimized $inputFile $args[0] $version $imageQuality }
    } elseif ($selectedMethod -like "*Font Subset*") {
        $useMethodName = "Method 1: Ghostscript Font Subset (90%+)"
        $useFunction   = { CompressMethod1_FontSubset_Aggressive $inputFile $args[0] $version }
    } elseif ($selectedMethod -like "*Balanced*") {
        $useMethodName = "Balanced (Text + Images)"
        $useFunction   = { CompressMethod_Balanced $inputFile $args[0] $version }
    } elseif ($selectedMethod -like "*Rebuild*") {
        $useMethodName = "Method 4: Rebuild from Text"
        $useFunction   = { CompressMethod4_Rebuild $inputFile $args[0] $version }
    } elseif ($selectedMethod -like "*Maximal + PDFtk*") {
        $useMethodName = "Method 5: Maximal + PDFtk Strip"
        $useFunction   = { CompressMethod5_MaximalPlusStrip $inputFile $args[0] $version }
    } else {
        $useMethodName = "Image Optimized ($imageQuality% Quality)"
        $useFunction   = { CompressMethod_ImageOptimized $inputFile $args[0] $version $imageQuality }
    }
    
    Write-Host "`nCompressing with $useMethodName..." -ForegroundColor Cyan
    Update-WorkingMessage "Working... Please wait (compressing with $useMethodName)..."
    
    $startTime = Get-Date
    $tempFile = [System.IO.Path]::GetTempFileName() + ".pdf"
    $success = & $useFunction $tempFile
    $elapsed = [math]::Round(((Get-Date) - $startTime).TotalSeconds, 0)
    
    if ($success -and (Test-Path $tempFile) -and (Get-ChildItem $tempFile).Length -gt 0) {
        $finalSize = (Get-ChildItem $tempFile).Length
        $finalMB   = [math]::Round($finalSize / 1MB, 2)
        $savedMB   = [math]::Round(($inputSize - $finalSize) / 1MB, 2)
        $savedPct  = [math]::Round((1 - $finalSize / $inputSize) * 100, 1)
        
        if ($savedPct -lt 0) {
            Write-Host "File size increased - using original file." -ForegroundColor Yellow
            Copy-Item $inputFile $outputFile -Force
        } else {
            Copy-Item $tempFile $outputFile -Force
        }
        Remove-Item $tempFile -Force -ErrorAction SilentlyContinue
        
        Write-Host "`n========================================" -ForegroundColor Green
        Write-Host "COMPRESSION COMPLETE" -ForegroundColor Green
        Write-Host "Method: $useMethodName" -ForegroundColor Green
        Write-Host "Original: $inputMB MB" -ForegroundColor Yellow
        Write-Host "Compressed: $finalMB MB" -ForegroundColor Yellow
        Write-Host "Saved: $savedMB MB ($savedPct%)" -ForegroundColor Green
        Write-Host "Time: ${elapsed}s" -ForegroundColor Cyan
        Write-Host "========================================" -ForegroundColor Green
        
        $msg = "Compression complete!`n`nMethod: $useMethodName`nImage Quality: $imageQuality%`nOriginal: $inputMB MB`nCompressed: $finalMB MB`nSaved: $savedMB MB ($savedPct%)`nTime: ${elapsed}s`n`nAnalysis: $($analysis.Reason)"
        [System.Windows.Forms.MessageBox]::Show($msg, "Compression Complete", "OK", "Information") | Out-Null
        return $true
    }
    
    Write-Host "Compression failed, saving original" -ForegroundColor Red
    Copy-Item $inputFile $outputFile -Force
    [System.Windows.Forms.MessageBox]::Show("Compression failed. The original file has been saved.", "Error", "OK", "Error") | Out-Null
    return $false
}

# ============= ULTRA FAST QPDF MERGE (UI-thread, popup) =============
function MergeFiles {
    param($files, $output)
    if ($files.Count -eq 0) { Write-Host "No files to merge" -ForegroundColor Red; return $false }
    if ($files.Count -eq 1) { Copy-Item $files[0] $output -Force; return (Test-Path $output) }
    
    $startTime = Get-Date
    $fileCount = $files.Count
    Write-Host "`n========================================" -ForegroundColor Cyan
    Write-Host "QPDF ULTRA FAST MERGE ENGINE" -ForegroundColor Green
    Write-Host "========================================" -ForegroundColor Cyan
    Write-Host "Files to merge: $fileCount" -ForegroundColor Yellow
    
    $missingFiles = @()
    foreach ($f in $files) { if (-not (Test-Path $f)) { $missingFiles += $f } }
    if ($missingFiles.Count -gt 0) {
        Write-Host "Missing files:" -ForegroundColor Red
        foreach ($f in $missingFiles) { Write-Host "  - $f" -ForegroundColor Red }
        return $false
    }
    
    Write-Host "`nGetting short paths..." -ForegroundColor Gray
    $shortPaths = @()
    foreach ($f in $files) {
        $shortPath = Get-ShortPath $f
        $shortPaths += $shortPath
        Write-Host "  $((Split-Path $f -Leaf)) -> $((Split-Path $shortPath -Leaf))" -ForegroundColor Gray
    }
    
    $pagesArg = ""
    foreach ($f in $shortPaths) { if ($pagesArg -ne "") { $pagesArg += " " }; $pagesArg += "`"$f`" ." }
    $args = "--empty --pages $pagesArg -- `"$output`""
    
    Write-Host "`n" + "="*60 -ForegroundColor Yellow
    Write-Host "QPDF COMMAND (INSTANT!)" -ForegroundColor Yellow
    Write-Host "="*60 -ForegroundColor Yellow
    Write-Host "$script:qpdf $args" -ForegroundColor White
    Write-Host "="*60 -ForegroundColor Yellow
    Write-Host ""
    
    Update-WorkingMessage "Working... Please wait (merging via QPDF)..."
    $res = Invoke-External -FileName $script:qpdf -Arguments $args
    if ($res.StdErr) { Write-Host "QPDF ERROR:`n$($res.StdErr)" -ForegroundColor Red }
    if ($res.StdOut) { Write-Host "QPDF OUTPUT:`n$($res.StdOut)" -ForegroundColor Gray }
    
    $elapsed = [math]::Round(((Get-Date) - $startTime).TotalSeconds, 3)
    if ($res.ExitCode -eq 0 -and (Test-Path $output) -and (Get-ChildItem $output).Length -gt 0) {
        $size = [math]::Round((Get-ChildItem $output).Length / 1MB, 2)
        Write-Host "`nSuccess! Time: ${elapsed}s, Size: $size MB" -ForegroundColor Green
        Write-Host "========================================" -ForegroundColor Green
        return $true
    }
    
    Write-Host "`nQPDF failed, trying PDFtk fallback..." -ForegroundColor Yellow
    Update-WorkingMessage "Working... Please wait (fallback to PDFtk)..."
    
    $fileList = ""
    foreach ($f in $shortPaths) { if ($fileList -ne "") { $fileList += " " }; $fileList += "`"$f`"" }
    $args2 = "$fileList cat output `"$output`""
    
    $res2 = Invoke-External -FileName $script:pdftk -Arguments $args2
    if ($res2.ExitCode -eq 0 -and (Test-Path $output) -and (Get-ChildItem $output).Length -gt 0) {
        $size = [math]::Round((Get-ChildItem $output).Length / 1MB, 2)
        Write-Host "`nPDFtk fallback success! Time: ${elapsed}s, Size: $size MB" -ForegroundColor Green
        Write-Host "========================================" -ForegroundColor Green
        return $true
    }
    
    Write-Host "`nMerge failed! Exit code: $($res.ExitCode)" -ForegroundColor Red
    Write-Host "========================================" -ForegroundColor Red
    return $false
}

